INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (1, '黑洞', '向黑洞投入的硬币转动着命运的星轨，神秘的物品从不知何处的白洞中倾泻而出。', 6666666, 0, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (2, '星环', '巨构星环沿着恒星缓慢转动，回收舰队将未知残骸投入熔炉，再由自动仓库吐出被标价的奇迹。', 0, 88, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (3, '仙境', '云雾缭绕之地有二，其一如仙境，其二乃魔地。然天机昭昭，俗眼难辨，是仙是魔砸了金币才知道。', 6666666, 0, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (4, '龙泉', '即便蛟龙也会被这通天龙瀑重创，小小鲤鱼为何敢于攀瀑？投入钻石的话，也许你也能明白了。', 0, 88, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (5, '深渊', '莫可名状的漆黑触手轻轻触碰到你的衣角，某种呼啸般的声音在呼唤着你深入。', 6666666, 0, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (6, '梦境', '金币如梦似幻地消失了，那么，你到底得到了什么呢？……', 0, 88, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (7, '位面', '位面裂隙短暂开启，异界商旅、失落遗物与未署名契约在此交汇。', 6666666, 0, 0, NULL);
INSERT INTO "gacha_pools" ("gacha_pool_id", "name", "description", "cost_coins", "cost_premium_currency", "is_limited_time", "open_until") VALUES (8, '龙窟', '古龙沉睡之地堆满王冠、断剑与失落秘宝，连尘埃都沾着魔力与诅咒。', 0, 88, 0, NULL);
